const i = $json || {};
const type = String(i.type || '').toLowerCase();
const value = i.value;
const out = { type, valid: false, sanitized: null, reason: null };

if (type === 'barcode') {
  const barcode = String(value || '').trim();
  out.sanitized = barcode;
  out.valid = /^\d{8,13}$/.test(barcode);
  out.reason = out.valid ? null : 'barcode_must_be_8_to_13_digits';
}
else if (type === 'price') {
  const min = Number(i.min ?? 1);
  const max = Number(i.max ?? 1000000000);
  const normalized = Number(String(value || '').replace(',', '.').trim());
  out.sanitized = normalized;
  out.valid = Number.isFinite(normalized) && normalized >= min && normalized <= max;
  out.reason = out.valid ? null : `price_out_of_bounds_${min}_${max}`;
}
else if (type === 'url') {
  const raw = String(value || '').trim();
  try {
    const u = new URL(raw);
    const allowHosts = String(i.allow_hosts || '').split(',').map(s => s.trim()).filter(Boolean);
    const httpsOnly = i.https_only !== false;
    const hostAllowed = allowHosts.length === 0 || allowHosts.includes(u.hostname);
    out.sanitized = u.toString();
    out.valid = (!httpsOnly || u.protocol === 'https:') && hostAllowed;
    out.reason = out.valid ? null : (u.protocol !== 'https:' ? 'url_must_be_https' : 'url_host_not_allowlisted');
  } catch {
    out.reason = 'invalid_url';
  }
}
else {
  out.reason = 'unsupported_type';
}

return [{ json: out }];
